// v1 receiver — accepts all payloads (HMAC deferred, see post-call workflow
// for the reason; n8n's Code-node vm sandbox does not expose 'crypto').
// Real-time monitoring is enterprise-only on this workspace tier so this
// listener is currently never invoked by ElevenLabs. Listener stays online
// for when the tier upgrades.
const item = $input.first();
const headers = item.json.headers || {};
const sigHeader = headers['elevenlabs-signature'] || headers['ElevenLabs-Signature'] || '';
const payload = typeof item.json.body === 'string' ? JSON.parse(item.json.body) : (item.json.body || item.json);

return [{json: {
  verified: null,
  verification_note: 'HMAC deferred — accepts all',
  signature_header_present: Boolean(sigHeader),
  received_at: new Date().toISOString(),
  payload
}}];
